  let tempDir: string;
  let vault: CrashVault;

  beforeEach(() => {
    tempDir = createTempDir();
    vault = new CrashVault({
      ...DEFAULT_CONFIG,
      crashVaultPath: join(tempDir, 'crashes'),
      workspaceRoot: tempDir,
    });
  });

  afterEach(() => {
    try {
      rmSync(tempDir, { recursive: true });
    } catch {
      // Ignore
